package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"log"
	"net"
	"net/http"
	"strings"
	"sync"
	"time"
)

type Role string

const (
	RolePlayer Role = "player"
	RoleMod    Role = "mod"
	RoleAdmin  Role = "admin"
)

type Client struct {
	ID       string
	Name     string
	Role     Role
	Conn     net.Conn
	Server   *Server
	SendMu   sync.Mutex
	RemoteIP string
}

type Server struct {
	mu      sync.RWMutex
	clients map[string]*Client
	banned  map[string]bool
}

type Message struct {
	Type    string `json:"type"`
	From    string `json:"from,omitempty"`
	Target  string `json:"target,omitempty"`
	Content string `json:"content,omitempty"`
	System  bool   `json:"system,omitempty"`
}

func NewServer() *Server {
	return &Server{
		clients: make(map[string]*Client),
		banned:  make(map[string]bool),
	}
}

func (s *Server) AddClient(c *Client) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.clients[c.ID] = c
}

func (s *Server) RemoveClient(id string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	delete(s.clients, id)
}

func (s *Server) GetClient(id string) (*Client, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	c, ok := s.clients[id]
	return c, ok
}

func (s *Server) Broadcast(msg Message) {
	s.mu.RLock()
	clients := make([]*Client, 0, len(s.clients))
	for _, c := range s.clients {
		clients = append(clients, c)
	}
	s.mu.RUnlock()

	for _, c := range clients {
		c.Send(msg)
	}
}

func (s *Server) Ban(id string) {
	s.mu.Lock()
	s.banned[id] = true
	s.mu.Unlock()
}

func (s *Server) IsBanned(id string) bool {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.banned[id]
}

func (c *Client) Send(msg Message) {
	c.SendMu.Lock()
	defer c.SendMu.Unlock()
	_ = json.NewEncoder(c.Conn).Encode(msg)
}

func (c *Client) Close() {
	_ = c.Conn.Close()
}

func hasAtLeastRole(actual, required Role) bool {
	order := map[Role]int{
		RolePlayer: 0,
		RoleMod:    1,
		RoleAdmin:  2,
	}
	return order[actual] >= order[required]
}

func parseRole(v string) Role {
	switch strings.ToLower(strings.TrimSpace(v)) {
	case "admin":
		return RoleAdmin
	case "mod", "moderator":
		return RoleMod
	default:
		return RolePlayer
	}
}

func handleCommand(c *Client, line string) bool {
	if !strings.HasPrefix(line, "/") {
		return false
	}

	parts := strings.Fields(line)
	if len(parts) == 0 {
		return true
	}

	cmd := strings.ToLower(strings.TrimPrefix(parts[0], "/"))

	switch cmd {
	case "kick":
		if !hasAtLeastRole(c.Role, RoleMod) {
			c.Send(Message{Type: "error", Content: "permission denied", System: true})
			return true
		}
		if len(parts) < 2 {
			c.Send(Message{Type: "error", Content: "usage: /kick <playerId>", System: true})
			return true
		}
		targetID := parts[1]
		target, ok := c.Server.GetClient(targetID)
		if !ok {
			c.Send(Message{Type: "error", Content: "target not found", System: true})
			return true
		}
		target.Send(Message{Type: "system", Content: "you were kicked", System: true})
		target.Close()
		c.Server.Broadcast(Message{
			Type:    "system",
			Content: fmt.Sprintf("%s kicked %s", c.Name, target.Name),
			System:  true,
		})
		return true

	case "ban":
		if !hasAtLeastRole(c.Role, RoleAdmin) {
			c.Send(Message{Type: "error", Content: "permission denied", System: true})
			return true
		}
		if len(parts) < 2 {
			c.Send(Message{Type: "error", Content: "usage: /ban <playerId>", System: true})
			return true
		}
		targetID := parts[1]
		c.Server.Ban(targetID)
		if target, ok := c.Server.GetClient(targetID); ok {
			target.Send(Message{Type: "system", Content: "you were banned", System: true})
			target.Close()
		}
		c.Server.Broadcast(Message{
			Type:    "system",
			Content: fmt.Sprintf("%s banned %s", c.Name, targetID),
			System:  true,
		})
		return true

	case "giveitems":
		if !hasAtLeastRole(c.Role, RoleAdmin) {
			c.Send(Message{Type: "error", Content: "permission denied", System: true})
			return true
		}
		if len(parts) < 4 {
			c.Send(Message{Type: "error", Content: "usage: /giveitems <playerId> <item> <amount>", System: true})
			return true
		}
		targetID := parts[1]
		item := parts[2]
		amount := parts[3]
		target, ok := c.Server.GetClient(targetID)
		if !ok {
			c.Send(Message{Type: "error", Content: "target not found", System: true})
			return true
		}
		target.Send(Message{
			Type:    "system",
			Content: fmt.Sprintf("you received %s x%s", item, amount),
			System:  true,
		})
		c.Send(Message{
			Type:    "system",
			Content: fmt.Sprintf("granted %s x%s to %s", item, amount, target.Name),
			System:  true,
		})
		return true

	default:
		c.Send(Message{Type: "error", Content: "unknown command", System: true})
		return true
	}
}

func handleClientConn(s *Server, conn net.Conn, headers http.Header) {
	defer conn.Close()

	id := headers.Get("X-Player-ID")
	if id == "" {
		id = fmt.Sprintf("guest-%d", time.Now().UnixNano())
	}
	name := headers.Get("X-Player-Name")
	if name == "" {
		name = id
	}
	role := parseRole(headers.Get("X-Role"))

	if s.IsBanned(id) {
		_ = json.NewEncoder(conn).Encode(Message{Type: "error", Content: "banned", System: true})
		return
	}

	client := &Client{
		ID:       id,
		Name:     name,
		Role:     role,
		Conn:     conn,
		Server:   s,
		RemoteIP: conn.RemoteAddr().String(),
	}

	s.AddClient(client)
	defer s.RemoveClient(client.ID)

	s.Broadcast(Message{
		Type:    "system",
		Content: fmt.Sprintf("%s joined as %s", client.Name, client.Role),
		System:  true,
	})

	scanner := bufio.NewScanner(conn)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}

		if handleCommand(client, line) {
			continue
		}

		s.Broadcast(Message{
			Type:    "chat",
			From:    client.Name,
			Content: line,
		})
	}

	s.Broadcast(Message{
		Type:    "system",
		Content: fmt.Sprintf("%s left", client.Name),
		System:  true,
	})
}

func main() {
	server := NewServer()

	ln, err := net.Listen("tcp", ":8080")
	if err != nil {
		log.Fatal(err)
	}
	defer ln.Close()

	log.Println("game server listening on :8080")

	for {
		conn, err := ln.Accept()
		if err != nil {
			continue
		}

		go func(c net.Conn) {
			reader := bufio.NewReader(c)
			headers := http.Header{}

			for {
				line, err := reader.ReadString('\n')
				if err != nil {
					_ = c.Close()
					return
				}
				line = strings.TrimSpace(line)
				if line == "" {
					break
				}
				parts := strings.SplitN(line, ":", 2)
				if len(parts) == 2 {
					headers.Add(strings.TrimSpace(parts[0]), strings.TrimSpace(parts[1]))
				}
			}

			handleClientConn(server, &bufferedConn{Conn: c, reader: reader}, headers)
		}(conn)
	}
}

type bufferedConn struct {
	net.Conn
	reader *bufio.Reader
}

func (b *bufferedConn) Read(p []byte) (int, error) {
	return b.reader.Read(p)
}